from flask import Flask, jsonify
import importlib.util
import os

app = Flask(__name__)

def load_routes_from_directory(directory):
    for root, dirs, files in os.walk(directory):
        for file in files:
            if file.endswith(".py") and not file.startswith("__"):
                module_path = os.path.join(root, file)
                module_name = os.path.splitext(os.path.basename(file))[0]

                # Génère un nom unique basé sur le chemin relatif
                rel_path = os.path.relpath(module_path, directory).replace(os.sep, ".").replace(".py", "")
                spec = importlib.util.spec_from_file_location(rel_path, module_path)
                module = importlib.util.module_from_spec(spec)
                try:
                    spec.loader.exec_module(module)
                    if hasattr(module, "register_routes"):
                        module.register_routes(app)
                except Exception as e:
                    print(f"⚠️ Erreur lors du chargement de {module_path} : {e}")

@app.route("/")
def index():
    return jsonify({"message": "Bienvenue dans laNostr'AI 🚀", "status": "ok"})

if __name__ == "__main__":
    print("🔄 Chargement dynamique des routes...")
    load_routes_from_directory("services")  # On peut rendre ce chemin configurable
    print("✅ Lancement du serveur Flask.")
    app.run(debug=True)
```

